import java.util.TreeMap;

public List<List<Integer>> splitPainting(int[][] segments) {
    TreeMap<Integer, Integer> line = new TreeMap<>();
    for (int[] s : segments) {
        int start = s[0];
        int end = s[1];
        int color = s[2];
        line.put(start, line.getOrDefault(start, 0) + color);
        line.put(end, line.getOrDefault(end, 0) - color);
    }
    List<List<Integer>> res = new ArrayList<>();
    int pre = 0, sum = 0;
    for (Map.Entry<Integer, Integer> entry : line.entrySet()) {
        if (pre > 0) {
            if (sum > 0) {
                List<Integer> temp = new ArrayList<>();
                temp.add(pre);
                temp.add(entry.getKey());
                temp.add(sum);
                res.add(temp);
            }
        }
        pre = entry.getKey();
        sum += entry.getValue();
    }
    return res;
}
